import React, { useState, useMemo } from 'react';
const MyComponent = () => {
  const [obj, setObj] = useState({ arr: [1, 2, 3] });
  const memoizedArray = useMemo(() => [...obj.arr], [obj]);
  return (
    <div>Re-renders: {memoizedArray}</div>
  );
};
export default MyComponent;

